using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap the JSONPlaceholder REST API.
/// Uses constructor injection — HttpClient and ILogger are resolved by the DI container.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private const string BaseUrl = "https://jsonplaceholder.typicode.com";

    [McpServerTool, Description("Get a post by its ID from the REST API.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post (1-100)")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {Id}", id);
        var post = await httpClient.GetFromJsonAsync<Post>(
            $"{BaseUrl}/posts/{id}", cancellationToken);

        return post is null
            ? $"Post {id} not found."
            : $"Title: {post.Title}\n\n{post.Body}";
    }

    [McpServerTool, Description("Search posts by user ID. Returns titles and IDs.")]
    public async Task<string> GetPostsByUser(
        [Description("The user ID to filter posts by (1-10)")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching posts for user {UserId}", userId);
        var posts = await httpClient.GetFromJsonAsync<List<Post>>(
            $"{BaseUrl}/posts?userId={userId}", cancellationToken);

        if (posts is null or { Count: 0 })
            return $"No posts found for user {userId}.";

        return string.Join("\n", posts.Select(p => $"[{p.Id}] {p.Title}"));
    }

    [McpServerTool, Description("Get comments for a specific post.")]
    public async Task<string> GetComments(
        [Description("The post ID to retrieve comments for")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching comments for post {PostId}", postId);
        var comments = await httpClient.GetFromJsonAsync<List<Comment>>(
            $"{BaseUrl}/posts/{postId}/comments", cancellationToken);

        if (comments is null or { Count: 0 })
            return $"No comments found for post {postId}.";

        return string.Join("\n---\n",
            comments.Select(c => $"From: {c.Email}\n{c.Body}"));
    }
}

public record Post(
    [property: JsonPropertyName("id")] int Id,
    [property: JsonPropertyName("userId")] int UserId,
    [property: JsonPropertyName("title")] string Title,
    [property: JsonPropertyName("body")] string Body);

public record Comment(
    [property: JsonPropertyName("id")] int Id,
    [property: JsonPropertyName("postId")] int PostId,
    [property: JsonPropertyName("name")] string Name,
    [property: JsonPropertyName("email")] string Email,
    [property: JsonPropertyName("body")] string Body);

